def overall_status(wf, skill, tests, fep, boot):
    """Calculate overall status."""
    score = 0
    if wf: score += 1
    if skill: score += 1
    if tests > 0: score += 1
    if fep: score += 1
    if boot: score += 1

    if score >= 5:
        return "◎"  # 完璧
    elif score >= 4:
        return "○"  # 良好
    elif score >= 3:
        return "△"  # 部分的
    elif score >= 1:
        return "▽"  # 不足
    else:
        return "✗"  # 未実装

