def _op_to_ccl(op: ast.operator) -> str:
    """二項演算子を CCL に変換。"""
    op_map = {
        ast.Add: "+", ast.Sub: "-", ast.Mult: "*", ast.Div: "/",
        ast.Mod: "%", ast.Pow: "**", ast.FloorDiv: "//",
        ast.BitOr: "|", ast.BitAnd: "&", ast.BitXor: "^",
        ast.LShift: "<<", ast.RShift: ">>",
    }
    return op_map.get(type(op), "op")

